uses core.date as date;
export function getValue(): boolean
begin
if (date.days(_ebx.record.AdditionalInformation.endOfValidity,date.now())>0)
then return false;
else
return true;

end

trigger.script:
uses core.http as client;
uses core.json as json;
uses core.list as list;
uses core.log as log;
uses core.http as http;

export procedure onBeforeCreate()
begin

	var request := client.createRequest('GoogleMaps');
	var apiKey := http.getConfigValue(request, 'Key');

	//Test if you have provided a key
	if not isNull(apiKey) then
	begin
		//Get the address values from the record

		var number := _ebx.record.Address.Number;
		var street := _ebx.record.Address.Street;
		var zipcode := _ebx.record.Address.Zipcode;
		var city := _ebx.record.Address.City;
		var country := _ebx.record.Address.Country;


		// create the complete address by concatenating the address values
		var completeaddress := number | ' ' | street | ' ' | zipcode | ' ' | city | ' ' | country.Alpha2Code ;

		// create a request to call API REST https://maps.googleapis.com/maps/api/geocode/json?address=ADDRESS&key=YOUR_API_KEY
		log.info(completeaddress);

		client.addParameter(request, 'address', completeaddress);
		client.addParameter(request, 'key', apiKey);
		// send GET request
		var response := client.get(request);
		var status := client.getStatusCode(response);
		// read the response
		var body := client.getJsonBody(response).asObject;
		var results := json.getArray(body, 'results');

		if(not(list.isEmpty(results))) then
		begin
			// get geometry
			var geometry := json.getObject(results[0].asObject, 'geometry');

			var locationtype := json.getString(geometry, 'location_type');

			log.info(locationtype);
			// get location
			var location := json.getObject(geometry, 'location');
			_ebx.record.Address.latitude := '' | json.getDecimal(location, 'lat');
			_ebx.record.Address.longitude := '' | json.getDecimal(location, 'lng');
		end


	end


end

