nodeConstraint.script:
uses core.message as messageContext;
uses core.locale as locale;
uses core.validation as validationContext;
uses core.string as string;
uses core.log as log;
uses core.math as math;

export procedure check(record : .Companies)
begin
var iban := string.toUpperCase(string.trim(record.BillingInformation.IBAN));
	iban := string.replaceAll(iban, ' ', '');

	if(string.isEmpty(iban)) then
	begin
		var userMessage := messageContext.ofBundleWarning('companies', 'iban.not.set');
		messageContext.addMessage(userMessage);
	end
	else
	begin
		var measured := iban | '#';
		var len := string.indexOf(measured, '#');

		log.info('IBAN received: ' | iban | ' (length=' | string.valueOf(len) | ')');

		var onlyAlphaNum := string.replaceAll(iban, '[^A-Z0-9]', '');
		var measuredClean := onlyAlphaNum | '#';
		var cleanLen := string.indexOf(measuredClean, '#');

		if cleanLen <> len then
		begin
			var userMessage := messageContext.ofBundleError('companies', 'iban.invalid.caracters');
			messageContext.addMessage(userMessage);
		end
		else if (len < 15i) or (len > 34i) then
		begin
			var userMessage := messageContext.ofBundleError('companies', 'iban.invalid.length');
			messageContext.addMessage(userMessage);
		end
		else
		begin
			var letters := 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
			var digits := '0123456789';
			var c1 := string.substring(iban, 0i, 1i);
			var c2 := string.substring(iban, 1i, 2i);
			if (string.indexOf(letters, c1) < 0i) or (string.indexOf(letters, c2) < 0i) then
			begin

				var userMessage := messageContext.ofBundleError('companies', 'iban.invalid.shouldStartWithIsoCode');
				messageContext.addMessage(userMessage);
			end
			else
			begin
				var c3 := string.substring(iban, 2i, 3i);
				var c4 := string.substring(iban, 3i, 4i);
				if (string.indexOf(digits, c3) < 0i) or (string.indexOf(digits, c4) < 0i) then
				begin
					var userMessage := messageContext.ofBundleError('companies', 'iban.invalid.position3and4areControlKeys');
					messageContext.addMessage(userMessage);
				end
				else
				begin
					var tail := string.substring(iban, 0i, 4i);
					var body := string.substring(iban, 4i, len);
					var rearranged := body | tail;

					var remainder := 0i;
					var idx := 0i;
					while idx < len do
					begin
						var ch := string.substring(rearranged, idx, idx + 1i);
						var letterPos := string.indexOf(letters, ch);
						if letterPos >= 0i then
						begin
							var numVal := letterPos + 10i;
							var t := remainder * 100i + numVal;
							remainder := t - math.floor(t / 97i) * 97i;
						end
						else
						begin
							var digitPos := string.indexOf(digits, ch);
							var t := remainder * 10i + digitPos;
							remainder := t - math.floor(t / 97i) * 97i;
						end
						idx := idx + 1i;
					end

					log.info('MOD-97 remainder: ' | string.valueOf(remainder));

					if remainder = 1i then
					begin

					end
					else
					begin
						var userMessage := messageContext.ofBundleError('companies', 'iban.invalid.mod97Fail');
						messageContext.addMessage(userMessage);
					end
				end
			end
		end

	end
end

export procedure setup()
begin 
end
